Here's a complete MSTest test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK)
        {
            Content = new StringContent("hello")
        });
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com",
            _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("hello", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.InternalServerError));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsTaskCanceledException()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.OK));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_SlowResponse_CancelledByTimeout()
    {
        // Arrange — handler delays longer than [Timeout]
        var handler = new FakeHandler(
            new HttpResponseMessage(HttpStatusCode.OK),
            delay: TimeSpan.FromSeconds(30));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert — TestContext.CancellationToken fires at 3s
        await Assert.ThrowsAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    // Minimal fake handler — no mocking library needed
    private sealed class FakeHandler(
        HttpResponseMessage response,
        TimeSpan delay = default) : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (delay > TimeSpan.Zero)
                await Task.Delay(delay, cancellationToken);

            return response;
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Cooperative timeout** | `[Timeout(ms)]` + pass `_testContext.CancellationToken` into `FetchAsync` |
| **Pre-cancelled token** | `cts.Cancel()` before the call to verify immediate cancellation |
| **Timeout-driven cancel** | Slow handler + short `[Timeout]` — the framework cancels the token automatically |
| **Exception assertion** | `ThrowsExactlyAsync` for exact type; `ThrowsAsync` when derived types (like `TaskCanceledException : OperationCanceledException`) are acceptable |
| **No mocking library** | A simple `FakeHandler` gives full control over `HttpClient` behavior |

The critical detail: always flow `TestContext.CancellationToken` (or your own `CancellationTokenSource.Token`) into the async method under test — without it, `[Timeout]` can't cooperatively cancel the work.
